/**
 * Options for struct initialization
 */
export interface Options {
    alignment?: number;
    isPacked?: boolean;
    /** Whether the struct is a union */
    isUnion?: boolean;
    isDynamic?: boolean;
}
/**
 * A shortcut for packing structs.
 */
export declare const packed: {
    isPacked: true;
};
/**
 * A shortcut for setting alignment
 */
export declare function align(n: number): Options;
